const now = new Date();
const months = ['janvier','février','mars','avril','mai','juin','juillet','août','septembre','octobre','novembre','décembre'];
const seasons = { 0:'hiver',1:'hiver',2:'printemps',3:'printemps',4:'printemps',5:'été',6:'été',7:'été',8:'automne',9:'automne',10:'automne',11:'hiver' };
const weekStart = new Date(now);
weekStart.setDate(now.getDate());
const dates = [];
for (let i = 0; i < 7; i++) {
  const d = new Date(weekStart);
  d.setDate(weekStart.getDate() + i);
  dates.push(d.toISOString().split('T')[0]);
}
return [{ json: { season: seasons[now.getMonth()], month: months[now.getMonth()], year: now.getFullYear(), week_dates: dates, iso_week: `${now.getFullYear()}-W${String(Math.ceil((now - new Date(now.getFullYear(),0,1)) / 604800000)).padStart(2,'0')}` } }];

const brand = $('Call Brand Memory Assembly').first().json;
const topPosts = $('Fetch Top 5 Posts').all();
const weather = $('Get Weather Forecast').first().json;
const context = $('Get Current Date Context').first().json;
const restaurant = $('Loop Over Restaurants').first().json;

const systemPrompt = `Tu es un social media manager expert spécialisé dans la restauration française. Tu crées des plannings éditoriaux engageants et variés.

RÈGLES:
- Génère exactement 7 posts pour la semaine
- Varie les types de contenu : plat_du_jour, coulisses, equipe, avis_client, promo, saisonnier, ambiance
- Varie les formats : single, carrousel, story, reel
- Varie les plateformes cibles : instagram, facebook, tiktok
- Ne répète jamais le même hook_type 2 fois de suite
- Adapte le contenu à la saison et à la météo
- Réponds UNIQUEMENT en JSON valide`;

const prompt = `RESTAURANT: ${brand.summary || restaurant.name}

POSTS LES PLUS PERFORMANTS (s'en inspirer):
${topPosts.map(p => `- [Score: ${p.json.performance_score}] ${p.json.content_type}: ${(p.json.caption || '').slice(0, 80)}`).join('\n') || 'Aucun historique disponible'}

MÉTÉO SEMAINE: ${JSON.stringify(weather.daily || 'Non disponible')}

CONTEXTE: Saison ${context.season}, ${context.month} ${context.year}
Dates de la semaine: ${(context.week_dates || []).join(', ')}

Génère un planning de 7 posts au format JSON:
[{
  "day_index": 0-6,
  "scheduled_date": "YYYY-MM-DD",
  "scheduled_time": "HH:MM",
  "content_type": "plat_du_jour|coulisses|equipe|avis_client|promo|saisonnier|ambiance",
  "format": "single|carrousel|story|reel",
  "platforms": ["instagram", "facebook"],
  "creative_brief": "Description courte du post",
  "hook_type": "question|affirmation|mise_en_scene|temoignage|coulisses|defi|chiffre",
  "structure_type": "hook_description_cta|contexte_revelation_invitation|question_reponse|story_mini"
}]`;

return [{ json: { system_prompt: systemPrompt, prompt: prompt, max_tokens: 2048, temperature: 0.7, restaurant_id: restaurant.id } }];

const response = $json.response;
let posts;
try {
  const jsonMatch = response.match(/\[[\s\S]*\]/);
  posts = JSON.parse(jsonMatch[0]);
} catch (e) {
  posts = JSON.parse(response);
}
if (!Array.isArray(posts) || posts.length !== 7) throw new Error('Expected 7 posts');
return posts.map(post => ({ json: post }));

const post = $json;
const restaurantId = $('Build Planning Prompt').first().json.restaurant_id;
const scheduledAt = `${post.scheduled_date}T${post.scheduled_time || '12:00'}:00+01:00`;
return {
  json: {
    restaurant_id: restaurantId,
    scheduled_at: scheduledAt,
    platforms: post.platforms || ['instagram', 'facebook'],
    content_type: post.content_type,
    format: post.format,
    creative_brief: post.creative_brief,
    hook_type: post.hook_type,
    structure_type: post.structure_type,
    status: 'planned'
  }
};
